#include <stdio.h>
#include <stdlib.h>

int main() {
    // Request memory from Memory Management service
    int *ptr1 = (int*)malloc(sizeof(int) * 10);
    int *ptr2 = (int*)malloc(sizeof(int) * 20);

    if (ptr1 == NULL || ptr2 == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Use the allocated memory
    for (int i = 0; i < 10; i++) {
        ptr1[i] = i * 2;
    }

    printf("Memory allocated successfully\n");

    // Release memory back to system
    free(ptr1);
    free(ptr2);

    return 0;
}

// Message Passing IPC Mechanism

// Process A sends message to Process B
FUNCTION SendMessage(receiverPID, message)
  BEGIN
    // Create message envelope
    msgEnvelope = CreateMessageEnvelope()
    msgEnvelope.sender = GetCurrentProcessID()
    msgEnvelope.receiver = receiverPID
    msgEnvelope.content = message
    msgEnvelope.timestamp = GetSystemTime()

    // Validate receiver exists
    IF NOT ProcessExists(receiverPID) THEN
      RETURN ERROR_INVALID_RECEIVER
    END IF

    // Add to receiver's message queue (through kernel)
    EnqueueMessage(receiverPID, msgEnvelope)

    // Notify receiver process
    SignalProcess(receiverPID, MESSAGE_ARRIVED)

    RETURN SUCCESS
  END

// Process B receives message
FUNCTION ReceiveMessage()
  BEGIN
    pid = GetCurrentProcessID()

    // Check message queue
    IF MessageQueueEmpty(pid) THEN
      // Block until message arrives
      WaitForSignal(MESSAGE_ARRIVED)
    END IF

    // Dequeue first message
    message = DequeueMessage(pid)

    RETURN message.content
  END
